const express = require('express');
const { updateDb } = require('../data/store');
const { requireAuth } = require('../middlewares/requireAuth');
const { asyncHandler } = require('../utils/asyncHandler');
const { sanitizeUser } = require('../utils/auth');

const router = express.Router();

function getEditableProfileFields(body = {}) {
  const editableFields = ['firstName', 'lastName', 'phone', 'company'];

  return editableFields.reduce((profile, field) => {
    if (body[field] !== undefined) {
      profile[field] = body[field];
    }

    return profile;
  }, {});
}

router.get('/profile', requireAuth, (req, res) => {
  res.json({ success: true, user: sanitizeUser(req.auth.user) });
});

router.put('/profile', requireAuth, asyncHandler(async (req, res) => {
  const profileFields = getEditableProfileFields(req.body);
  const nextDb = await updateDb((draft) => {
    draft.users = draft.users.map((user) => (
      user.id === req.auth.user.id ? { ...user, ...profileFields } : user
    ));
  });
  const user = nextDb.users.find((candidate) => candidate.id === req.auth.user.id);

  res.json({ success: true, user: sanitizeUser(user) });
}));

router.get('/addresses', requireAuth, (req, res) => {
  res.json({ success: true, addresses: req.auth.user.addresses || [] });
});

router.put('/addresses', requireAuth, asyncHandler(async (req, res) => {
  const addresses = Array.isArray(req.body?.addresses) ? req.body.addresses : [];
  const nextDb = await updateDb((draft) => {
    draft.users = draft.users.map((user) => (
      user.id === req.auth.user.id ? { ...user, addresses } : user
    ));
  });
  const user = nextDb.users.find((candidate) => candidate.id === req.auth.user.id);

  res.json({ success: true, user: sanitizeUser(user), addresses: user.addresses || [] });
}));

router.get('/payments', requireAuth, (req, res) => {
  res.json({ success: true, paymentMethods: req.auth.user.paymentMethods || [] });
});

module.exports = router;
